# solution.py
"""TeamCollaborationManager - an in-memory, thread-safe collaboration backend.

This module implements a team collaboration manager that supports:

* User accounts with roles (member / admin) and full CRUD.
* Projects owned by users, with cascading deletes.
* Tasks with assignment, deadlines and a status lifecycle
  (not started -> in progress -> completed).
* A threaded messaging system supporting project/task scopes, replies and
  binary attachments.
* A performance dashboard with completion rates, average completion time and
  peer ratings.
* Reporting (project progress, team performance, individual performance) with
  CSV and PDF export.

All public operations are guarded by a single shared re-entrant lock so the
manager and its sub-stores can be safely used from multiple threads.  Every
getter returns a deep copy so callers cannot mutate the internal store.

Standard library only, ASCII only.
"""

import copy
import csv
import io
import threading
from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum
from typing import Dict, List, Optional


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class UserRole(Enum):
    """Access level for a user account."""

    MEMBER = "member"
    ADMIN = "admin"


class TaskStatus(Enum):
    """Lifecycle states for a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class ReportFormat(Enum):
    """Supported export formats for reports."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    """Kinds of reports the manager can produce."""

    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for all collaboration-manager errors."""


class ValidationError(TeamCollaborationError):
    """Raised when input fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an operation."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint would be violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with current state."""


# ---------------------------------------------------------------------------
# Data entities
# ---------------------------------------------------------------------------
@dataclass
class User:
    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    id: int
    name: str
    description: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    created_at: datetime


@dataclass
class Task:
    id: int
    project_id: int
    title: str
    status: TaskStatus
    assignee_id: Optional[int]
    deadline: Optional[datetime]
    created_at: datetime
    started_at: Optional[datetime] = None
    completed_at: Optional[datetime] = None


@dataclass
class Attachment:
    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class Message:
    id: int
    author_id: int
    body: str
    project_id: Optional[int]
    task_id: Optional[int]
    parent_id: Optional[int]
    created_at: datetime
    edited_at: Optional[datetime] = None
    attachments: List[Attachment] = field(default_factory=list)


@dataclass
class Rating:
    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str
    task_id: Optional[int]
    created_at: datetime


# ---------------------------------------------------------------------------
# Sub-stores (data holders that all share the manager's lock)
# ---------------------------------------------------------------------------
class UserStore:
    def __init__(self, lock):
        self._lock = lock
        self._items: Dict[int, User] = {}
        self._by_username: Dict[str, int] = {}
        self._by_email: Dict[str, int] = {}


class ProjectStore:
    def __init__(self, lock):
        self._lock = lock
        self._items: Dict[int, Project] = {}


class TaskStore:
    def __init__(self, lock):
        self._lock = lock
        self._items: Dict[int, Task] = {}
        self._by_project: Dict[int, List[int]] = {}
        self._by_assignee: Dict[int, List[int]] = {}


class MessageStore:
    def __init__(self, lock):
        self._lock = lock
        self._items: Dict[int, Message] = {}
        self._by_project: Dict[int, List[int]] = {}
        self._by_task: Dict[int, List[int]] = {}


class PerformanceService:
    def __init__(self, lock):
        self._lock = lock
        self._ratings: Dict[int, List[Rating]] = {}


class ReportService:
    def __init__(self, lock):
        self._lock = lock


# ---------------------------------------------------------------------------
# Manager
# ---------------------------------------------------------------------------
class TeamCollaborationManager:
    """Thread-safe facade over the collaboration sub-stores."""

    def __init__(self, now=None):
        # A single re-entrant lock is shared by the manager and every store so
        # cross-store operations remain atomic and the lock identity is stable.
        self._lock = threading.RLock()
        self._now = now if now is not None else datetime.now
        self._id_counter = 0

        self.users = UserStore(self._lock)
        self.projects = ProjectStore(self._lock)
        self.tasks = TaskStore(self._lock)
        self.messages = MessageStore(self._lock)
        self.performance = PerformanceService(self._lock)
        self.reports = ReportService(self._lock)

    # -- internal helpers --------------------------------------------------
    def _next_id(self) -> int:
        with self._lock:
            self._id_counter += 1
            return self._id_counter

    def _clock(self) -> datetime:
        return self._now()

    @staticmethod
    def _clone(obj):
        return copy.deepcopy(obj)

    def _require_user(self, user_id) -> User:
        user = self.users._items.get(user_id)
        if user is None:
            raise NotFoundError("User {0} not found".format(user_id))
        return user

    def _require_project(self, project_id) -> Project:
        project = self.projects._items.get(project_id)
        if project is None:
            raise NotFoundError("Project {0} not found".format(project_id))
        return project

    def _require_task(self, task_id) -> Task:
        task = self.tasks._items.get(task_id)
        if task is None:
            raise NotFoundError("Task {0} not found".format(task_id))
        return task

    def _require_message(self, message_id) -> Message:
        message = self.messages._items.get(message_id)
        if message is None:
            raise NotFoundError("Message {0} not found".format(message_id))
        return message

    @staticmethod
    def _validate_email(email):
        if not isinstance(email, str) or not email.strip():
            raise ValidationError("Email must be a non-empty string")
        if "@" not in email:
            raise ValidationError("Email must contain '@'")
        return email.strip()

    @staticmethod
    def _validate_name(value, label):
        if not isinstance(value, str) or not value.strip():
            raise ValidationError("{0} must be a non-empty string".format(label))
        return value.strip()

    def _set_assignee(self, task: Task, new_assignee_id: Optional[int]):
        old = task.assignee_id
        if old is not None and old in self.tasks._by_assignee:
            bucket = self.tasks._by_assignee[old]
            if task.id in bucket:
                bucket.remove(task.id)
            if not bucket:
                del self.tasks._by_assignee[old]
        task.assignee_id = new_assignee_id
        if new_assignee_id is not None:
            self.tasks._by_assignee.setdefault(new_assignee_id, []).append(task.id)

    # ------------------------------------------------------------------
    # User management
    # ------------------------------------------------------------------
    def register_user(self, username, email, role=UserRole.MEMBER) -> User:
        with self._lock:
            username = self._validate_name(username, "Username")
            email = self._validate_email(email)
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")
            if username in self.users._by_username:
                raise DuplicateError("Username already exists")
            if email in self.users._by_email:
                raise DuplicateError("Email already exists")

            user = User(
                id=self._next_id(),
                username=username,
                email=email,
                role=role,
                created_at=self._clock(),
            )
            self.users._items[user.id] = user
            self.users._by_username[username] = user.id
            self.users._by_email[email] = user.id
            return self._clone(user)

    def get_user(self, user_id) -> User:
        with self._lock:
            return self._clone(self._require_user(user_id))

    def list_users(self) -> List[User]:
        with self._lock:
            return [
                self._clone(self.users._items[uid])
                for uid in sorted(self.users._items)
            ]

    def update_user(self, user_id, username=None, email=None, role=None) -> User:
        with self._lock:
            user = self._require_user(user_id)

            if username is not None:
                username = self._validate_name(username, "Username")
                existing = self.users._by_username.get(username)
                if existing is not None and existing != user.id:
                    raise DuplicateError("Username already exists")

            if email is not None:
                email = self._validate_email(email)
                existing = self.users._by_email.get(email)
                if existing is not None and existing != user.id:
                    raise DuplicateError("Email already exists")

            if role is not None and not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            if username is not None and username != user.username:
                del self.users._by_username[user.username]
                user.username = username
                self.users._by_username[username] = user.id

            if email is not None and email != user.email:
                del self.users._by_email[user.email]
                user.email = email
                self.users._by_email[email] = user.id

            if role is not None:
                user.role = role

            return self._clone(user)

    def delete_user(self, user_id) -> None:
        with self._lock:
            user = self._require_user(user_id)

            for project in self.projects._items.values():
                if project.owner_id == user.id:
                    raise ConflictError("User owns a project")

            assigned = self.tasks._by_assignee.get(user.id, [])
            for tid in assigned:
                task = self.tasks._items.get(tid)
                if task is not None and task.status != TaskStatus.COMPLETED:
                    raise ConflictError("User has an open task")

            # Detach any remaining (completed) tasks from the assignee index.
            for tid in list(assigned):
                task = self.tasks._items.get(tid)
                if task is not None:
                    task.assignee_id = None
            self.tasks._by_assignee.pop(user.id, None)

            del self.users._items[user.id]
            self.users._by_username.pop(user.username, None)
            self.users._by_email.pop(user.email, None)

    # ------------------------------------------------------------------
    # Project management
    # ------------------------------------------------------------------
    def create_project(
        self, name, start_date, end_date, owner_id, description=""
    ) -> Project:
        with self._lock:
            name = self._validate_name(name, "Project name")
            if end_date < start_date:
                raise ValidationError("end_date cannot precede start_date")
            self._require_user(owner_id)

            project = Project(
                id=self._next_id(),
                name=name,
                description=description if description is not None else "",
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                created_at=self._clock(),
            )
            self.projects._items[project.id] = project
            self.tasks._by_project.setdefault(project.id, [])
            self.messages._by_project.setdefault(project.id, [])
            return self._clone(project)

    def get_project(self, project_id) -> Project:
        with self._lock:
            return self._clone(self._require_project(project_id))

    def list_projects(self) -> List[Project]:
        with self._lock:
            return [
                self._clone(self.projects._items[pid])
                for pid in sorted(self.projects._items)
            ]

    def update_project(
        self, project_id, name=None, start_date=None, end_date=None, description=None
    ) -> Project:
        with self._lock:
            project = self._require_project(project_id)

            new_name = project.name
            if name is not None:
                new_name = self._validate_name(name, "Project name")

            new_start = start_date if start_date is not None else project.start_date
            new_end = end_date if end_date is not None else project.end_date
            if new_end < new_start:
                raise ValidationError("end_date cannot precede start_date")

            project.name = new_name
            project.start_date = new_start
            project.end_date = new_end
            if description is not None:
                project.description = description
            return self._clone(project)

    def delete_project(self, project_id) -> None:
        with self._lock:
            project = self._require_project(project_id)

            task_ids = list(self.tasks._by_project.get(project.id, []))
            for tid in task_ids:
                self._purge_task(tid)
            self.tasks._by_project.pop(project.id, None)

            msg_ids = list(self.messages._by_project.get(project.id, []))
            for mid in msg_ids:
                self._purge_message(mid)
            self.messages._by_project.pop(project.id, None)

            del self.projects._items[project.id]

    def _purge_task(self, task_id) -> None:
        task = self.tasks._items.pop(task_id, None)
        if task is None:
            return
        if task.assignee_id is not None:
            bucket = self.tasks._by_assignee.get(task.assignee_id)
            if bucket and task_id in bucket:
                bucket.remove(task_id)
                if not bucket:
                    del self.tasks._by_assignee[task.assignee_id]
        project_bucket = self.tasks._by_project.get(task.project_id)
        if project_bucket and task_id in project_bucket:
            project_bucket.remove(task_id)
        for mid in list(self.messages._by_task.get(task_id, [])):
            self._purge_message(mid)
        self.messages._by_task.pop(task_id, None)

    def _purge_message(self, message_id) -> None:
        message = self.messages._items.pop(message_id, None)
        if message is None:
            return
        if message.project_id is not None:
            bucket = self.messages._by_project.get(message.project_id)
            if bucket and message_id in bucket:
                bucket.remove(message_id)
        if message.task_id is not None:
            bucket = self.messages._by_task.get(message.task_id)
            if bucket and message_id in bucket:
                bucket.remove(message_id)

    # ------------------------------------------------------------------
    # Task management
    # ------------------------------------------------------------------
    def create_task(
        self, project_id, title, assignee_id=None, deadline=None
    ) -> Task:
        with self._lock:
            project = self._require_project(project_id)
            title = self._validate_name(title, "Task title")
            if assignee_id is not None:
                self._require_user(assignee_id)
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline cannot precede project start")

            task = Task(
                id=self._next_id(),
                project_id=project_id,
                title=title,
                status=TaskStatus.NOT_STARTED,
                assignee_id=None,
                deadline=deadline,
                created_at=self._clock(),
            )
            self.tasks._items[task.id] = task
            self.tasks._by_project.setdefault(project_id, []).append(task.id)
            if assignee_id is not None:
                self._set_assignee(task, assignee_id)
            return self._clone(task)

    def get_task(self, task_id) -> Task:
        with self._lock:
            return self._clone(self._require_task(task_id))

    def list_tasks_by_project(self, project_id) -> List[Task]:
        with self._lock:
            self._require_project(project_id)
            ids = sorted(self.tasks._by_project.get(project_id, []))
            return [self._clone(self.tasks._items[tid]) for tid in ids]

    def list_tasks_by_assignee(self, assignee_id) -> List[Task]:
        with self._lock:
            self._require_user(assignee_id)
            ids = sorted(self.tasks._by_assignee.get(assignee_id, []))
            return [self._clone(self.tasks._items[tid]) for tid in ids]

    def assign_task(self, task_id, assignee_id) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(assignee_id)
            self._set_assignee(task, assignee_id)
            return self._clone(task)

    def reassign_task(self, task_id, new_assignee_id) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(new_assignee_id)
            self._set_assignee(task, new_assignee_id)
            return self._clone(task)

    def unassign_task(self, task_id) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._set_assignee(task, None)
            return self._clone(task)

    def set_deadline(self, task_id, deadline) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            if deadline is not None:
                project = self.projects._items.get(task.project_id)
                if project is not None and deadline < project.start_date:
                    raise ValidationError("deadline cannot precede project start")
            task.deadline = deadline
            return self._clone(task)

    def update_status(self, task_id, status) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")

            now = self._clock()
            if status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            else:  # NOT_STARTED
                task.started_at = None
                task.completed_at = None

            task.status = status
            return self._clone(task)

    # ------------------------------------------------------------------
    # Messaging
    # ------------------------------------------------------------------
    def post_message(
        self,
        author_id,
        body,
        project_id=None,
        task_id=None,
        parent_id=None,
        attachments=None,
    ) -> Message:
        with self._lock:
            self._require_user(author_id)

            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "Exactly one of project_id or task_id is required"
                )
            if project_id is not None:
                self._require_project(project_id)
            if task_id is not None:
                self._require_task(task_id)
            if parent_id is not None:
                self._require_message(parent_id)

            built = self._build_attachments(attachments, author_id)
            if (body is None or not str(body).strip()) and not built:
                raise ValidationError("Message body or attachment is required")

            message = Message(
                id=self._next_id(),
                author_id=author_id,
                body="" if body is None else str(body),
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                created_at=self._clock(),
                edited_at=None,
                attachments=built,
            )
            self.messages._items[message.id] = message
            if project_id is not None:
                self.messages._by_project.setdefault(project_id, []).append(message.id)
            if task_id is not None:
                self.messages._by_task.setdefault(task_id, []).append(message.id)
            return self._clone(message)

    def _build_attachments(self, attachments, uploader_id) -> List[Attachment]:
        built: List[Attachment] = []
        if not attachments:
            return built
        now = self._clock()
        for entry in attachments:
            filename, data = entry
            filename = self._validate_name(filename, "Attachment filename")
            size = len(data) if data is not None else 0
            built.append(
                Attachment(
                    filename=filename,
                    size=size,
                    uploaded_by=uploader_id,
                    uploaded_at=now,
                )
            )
        return built

    def edit_message(self, message_id, editor_id, new_body) -> Message:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("Only the author may edit a message")
            if new_body is None or not str(new_body).strip():
                raise ValidationError("Message body must be non-empty")
            message.body = str(new_body)
            message.edited_at = self._clock()
            return self._clone(message)

    def add_attachment(self, message_id, uploader_id, filename, data) -> Message:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != uploader_id:
                raise AuthorizationError("Only the author may add attachments")
            filename = self._validate_name(filename, "Attachment filename")
            size = len(data) if data is not None else 0
            message.attachments.append(
                Attachment(
                    filename=filename,
                    size=size,
                    uploaded_by=uploader_id,
                    uploaded_at=self._clock(),
                )
            )
            return self._clone(message)

    def list_messages_by_project(self, project_id) -> List[Message]:
        with self._lock:
            self._require_project(project_id)
            ids = sorted(self.messages._by_project.get(project_id, []))
            return [self._clone(self.messages._items[mid]) for mid in ids]

    def list_messages_by_task(self, task_id) -> List[Message]:
        with self._lock:
            self._require_task(task_id)
            ids = sorted(self.messages._by_task.get(task_id, []))
            return [self._clone(self.messages._items[mid]) for mid in ids]

    def delete_message(self, message_id, requester_id) -> None:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != requester_id:
                raise AuthorizationError("Only the author may delete a message")
            self._purge_message(message_id)

    # ------------------------------------------------------------------
    # Performance dashboard
    # ------------------------------------------------------------------
    def _assignee_tasks(self, user_id) -> List[Task]:
        ids = self.tasks._by_assignee.get(user_id, [])
        return [self.tasks._items[tid] for tid in ids if tid in self.tasks._items]

    @staticmethod
    def _completion_rate(tasks) -> float:
        if not tasks:
            return 0.0
        completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
        return completed / len(tasks)

    @staticmethod
    def _average_completion_time(tasks) -> Optional[float]:
        durations = [
            (t.completed_at - t.started_at).total_seconds()
            for t in tasks
            if t.status == TaskStatus.COMPLETED
            and t.started_at is not None
            and t.completed_at is not None
        ]
        if not durations:
            return None
        return sum(durations) / len(durations)

    def get_completion_rate(self, user_id) -> float:
        with self._lock:
            self._require_user(user_id)
            return self._completion_rate(self._assignee_tasks(user_id))

    def get_average_completion_time(self, user_id) -> Optional[float]:
        with self._lock:
            self._require_user(user_id)
            return self._average_completion_time(self._assignee_tasks(user_id))

    def submit_rating(self, rater_id, ratee_id, score, feedback="", task_id=None) -> Rating:
        with self._lock:
            self._require_user(rater_id)
            self._require_user(ratee_id)
            if rater_id == ratee_id:
                raise ConflictError("A user cannot rate themselves")
            if not isinstance(score, int) or isinstance(score, bool):
                raise ValidationError("score must be an integer")
            if score < 1 or score > 5:
                raise ValidationError("score must be between 1 and 5")
            if task_id is not None:
                self._require_task(task_id)

            rating = Rating(
                id=self._next_id(),
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback if feedback is not None else "",
                task_id=task_id,
                created_at=self._clock(),
            )
            self.performance._ratings.setdefault(ratee_id, []).append(rating)
            return self._clone(rating)

    def get_ratings_summary(self, user_id) -> dict:
        with self._lock:
            self._require_user(user_id)
            ratings = self.performance._ratings.get(user_id, [])
            count = len(ratings)
            average = (
                sum(r.score for r in ratings) / count if count else 0.0
            )
            return {
                "count": count,
                "average": average,
                "ratings": [self._clone(r) for r in ratings],
            }

    def get_user_dashboard(self, user_id) -> dict:
        with self._lock:
            self._require_user(user_id)
            tasks = self._assignee_tasks(user_id)
            ratings = self.performance._ratings.get(user_id, [])
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count
                if rating_count
                else 0.0
            )
            return {
                "user_id": user_id,
                "total_tasks": len(tasks),
                "completed_tasks": sum(
                    1 for t in tasks if t.status == TaskStatus.COMPLETED
                ),
                "in_progress_tasks": sum(
                    1 for t in tasks if t.status == TaskStatus.IN_PROGRESS
                ),
                "not_started_tasks": sum(
                    1 for t in tasks if t.status == TaskStatus.NOT_STARTED
                ),
                "completion_rate": self._completion_rate(tasks),
                "average_completion_time": self._average_completion_time(tasks),
                "rating_count": rating_count,
                "rating_average": rating_average,
            }

    # ------------------------------------------------------------------
    # Reports
    # ------------------------------------------------------------------
    def project_progress_report(self, project_id) -> dict:
        with self._lock:
            project = self._require_project(project_id)
            ids = self.tasks._by_project.get(project_id, [])
            tasks = [self.tasks._items[tid] for tid in ids if tid in self.tasks._items]
            now = self._clock()

            status_counts = {status.value: 0 for status in TaskStatus}
            overdue = 0
            per_assignee: Dict[int, dict] = {}
            for task in tasks:
                status_counts[task.status.value] += 1
                if (
                    task.deadline is not None
                    and task.deadline < now
                    and task.status != TaskStatus.COMPLETED
                ):
                    overdue += 1
                if task.assignee_id is not None:
                    bucket = per_assignee.setdefault(
                        task.assignee_id, {"total": 0, "completed": 0}
                    )
                    bucket["total"] += 1
                    if task.status == TaskStatus.COMPLETED:
                        bucket["completed"] += 1

            for bucket in per_assignee.values():
                total = bucket["total"]
                bucket["completion_rate"] = (
                    bucket["completed"] / total if total else 0.0
                )

            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project.id,
                "project_name": project.name,
                "total_tasks": len(tasks),
                "status_counts": status_counts,
                "completion_rate": self._completion_rate(tasks),
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(self, project_id=None) -> dict:
        with self._lock:
            if project_id is not None:
                self._require_project(project_id)
                ids = self.tasks._by_project.get(project_id, [])
                scope_tasks = [
                    self.tasks._items[tid] for tid in ids if tid in self.tasks._items
                ]
                scope = "project:{0}".format(project_id)
            else:
                scope_tasks = list(self.tasks._items.values())
                scope = "global"

            user_ids = sorted(
                {t.assignee_id for t in scope_tasks if t.assignee_id is not None}
            )
            rows = []
            for uid in user_ids:
                user_tasks = [t for t in scope_tasks if t.assignee_id == uid]
                ratings = self.performance._ratings.get(uid, [])
                rating_count = len(ratings)
                rating_average = (
                    sum(r.score for r in ratings) / rating_count
                    if rating_count
                    else 0.0
                )
                user = self.users._items.get(uid)
                rows.append(
                    {
                        "user_id": uid,
                        "username": user.username if user else "",
                        "total_tasks": len(user_tasks),
                        "completed_tasks": sum(
                            1
                            for t in user_tasks
                            if t.status == TaskStatus.COMPLETED
                        ),
                        "completion_rate": self._completion_rate(user_tasks),
                        "average_completion_time": self._average_completion_time(
                            user_tasks
                        ),
                        "rating_count": rating_count,
                        "rating_average": rating_average,
                    }
                )

            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "scope": scope,
                "rows": rows,
            }

    def individual_performance_report(self, user_id) -> dict:
        with self._lock:
            user = self._require_user(user_id)
            tasks = self._assignee_tasks(user_id)
            ratings = self.performance._ratings.get(user_id, [])
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count
                if rating_count
                else 0.0
            )
            task_rows = []
            for task in sorted(tasks, key=lambda t: t.id):
                task_rows.append(
                    {
                        "task_id": task.id,
                        "project_id": task.project_id,
                        "title": task.title,
                        "status": task.status.value,
                        "deadline": (
                            task.deadline.isoformat()
                            if task.deadline is not None
                            else ""
                        ),
                        "started_at": (
                            task.started_at.isoformat()
                            if task.started_at is not None
                            else ""
                        ),
                        "completed_at": (
                            task.completed_at.isoformat()
                            if task.completed_at is not None
                            else ""
                        ),
                    }
                )

            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user.id,
                "username": user.username,
                "total_tasks": len(tasks),
                "completed_tasks": sum(
                    1 for t in tasks if t.status == TaskStatus.COMPLETED
                ),
                "in_progress_tasks": sum(
                    1 for t in tasks if t.status == TaskStatus.IN_PROGRESS
                ),
                "not_started_tasks": sum(
                    1 for t in tasks if t.status == TaskStatus.NOT_STARTED
                ),
                "completion_rate": self._completion_rate(tasks),
                "average_completion_time": self._average_completion_time(tasks),
                "rating_count": rating_count,
                "rating_average": rating_average,
                "tasks": task_rows,
            }

    # ------------------------------------------------------------------
    # Report export
    # ------------------------------------------------------------------
    def export_report(self, report, report_format):
        with self._lock:
            if not isinstance(report, dict):
                raise ValidationError("report must be a dict")
            if not isinstance(report_format, ReportFormat):
                raise ValidationError("report_format must be a ReportFormat")

            if report_format == ReportFormat.CSV:
                return self._report_to_csv(report)
            return self._report_to_pdf(report)

    @staticmethod
    def _report_to_csv(report) -> str:
        output = io.StringIO()
        writer = csv.writer(output)

        table = None
        for key in ("rows", "tasks"):
            value = report.get(key)
            if isinstance(value, list):
                table = value
                break

        if table is not None:
            columns: List[str] = []
            for item in table:
                if isinstance(item, dict):
                    for col in item:
                        if col not in columns:
                            columns.append(col)
            if not columns:
                writer.writerow(["report_type"])
                writer.writerow([report.get("report_type", "")])
            else:
                writer.writerow(columns)
                for item in table:
                    writer.writerow([item.get(col, "") for col in columns])
        else:
            writer.writerow(["field", "value"])
            for key, value in report.items():
                writer.writerow([key, value])

        return output.getvalue()

    def _report_to_pdf(self, report) -> bytes:
        return self._build_pdf(self._report_lines(report))

    @staticmethod
    def _report_lines(report) -> List[str]:
        lines = ["Report Type: {0}".format(report.get("report_type", "report"))]
        for key, value in report.items():
            if key == "report_type":
                continue
            if isinstance(value, dict):
                lines.append("{0}:".format(key))
                for sub_key, sub_value in value.items():
                    lines.append("  {0}: {1}".format(sub_key, sub_value))
            elif isinstance(value, list):
                lines.append("{0}: {1} item(s)".format(key, len(value)))
                for item in value:
                    lines.append("  - {0}".format(item))
            else:
                lines.append("{0}: {1}".format(key, value))
        return lines

    @staticmethod
    def _pdf_escape(text) -> bytes:
        ascii_text = str(text).encode("ascii", "replace").decode("ascii")
        ascii_text = (
            ascii_text.replace("\\", "\\\\")
            .replace("(", "\\(")
            .replace(")", "\\)")
        )
        return ascii_text.encode("ascii")

    @classmethod
    def _build_pdf(cls, lines) -> bytes:
        content_parts = [b"BT", b"/F1 12 Tf", b"72 720 Td", b"14 TL"]
        first = True
        for line in lines:
            escaped = cls._pdf_escape(line)
            if first:
                content_parts.append(b"(" + escaped + b") Tj")
                first = False
            else:
                content_parts.append(b"T*")
                content_parts.append(b"(" + escaped + b") Tj")
        content_parts.append(b"ET")
        content = b"\n".join(content_parts)

        objects = [
            b"<< /Type /Catalog /Pages 2 0 R >>",
            b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
            b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
            b"/Contents 4 0 R /Resources << /Font << /F1 5 0 R >> >> >>",
            b"<< /Length "
            + str(len(content)).encode("ascii")
            + b" >>\nstream\n"
            + content
            + b"\nendstream",
            b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
        ]

        pdf = bytearray(b"%PDF-1.4\n")
        offsets = []
        for index, body in enumerate(objects, start=1):
            offsets.append(len(pdf))
            pdf += str(index).encode("ascii") + b" 0 obj\n" + body + b"\nendobj\n"

        xref_pos = len(pdf)
        size = len(objects) + 1
        pdf += b"xref\n"
        pdf += b"0 " + str(size).encode("ascii") + b"\n"
        pdf += b"0000000000 65535 f \n"
        for offset in offsets:
            pdf += ("%010d 00000 n \n" % offset).encode("ascii")
        pdf += b"trailer\n"
        pdf += b"<< /Size " + str(size).encode("ascii") + b" /Root 1 0 R >>\n"
        pdf += b"startxref\n"
        pdf += str(xref_pos).encode("ascii") + b"\n"
        pdf += b"%%EOF"
        return bytes(pdf)


